#include <bits/stdc++.h>
using namespace std;
const int maxn=505,kd[][2]= {{1,0},{-1,0},{0,1},{0,-1}};
int n,m,aa,bb,a[maxn][maxn],lst[maxn*maxn][2],len;
void check(int x,int y,int step) {
	if(x>=1&&x<=n&&y<=m&&y>=1&&!a[x][y]) {
		a[x][y]=step;
		lst[++len][0]=x,lst[len][1]=y;
	}
}
int main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n>>m>>aa>>bb;
	for(int i=1,x,y; i<=aa; i++) {
		cin>>x>>y;
		check(x,y,1);
	}
	for(int i=1; i<=len; ++i) {
		for(int j=0; j<4; ++j) {
			int dx=lst[i][0]+kd[j][0],dy=lst[i][1]+kd[j][1];
			check(dx,dy,a[lst[i][0]][lst[i][1]]+1);
		}
	}
	for(int i=1,x,y; i<=bb; ++i) {
		cin>>x>>y;
		cout<<a[x][y]-1<<"\n";
	}
	return 0;
}
